namespace optiling {

static constexpr uint32_t ALIGN_ELEMS = 64;  // conservative alignment

static ge::graphStatus TilingFunc(gert::TilingContext *context)
{
    VanillaRnnHiddenCustomTilingData tiling;

    // Extract shapes from input tensors
    auto x_shape = context->GetInputShape(0)->GetOriginShape();
    auto h0_shape = context->GetInputShape(1)->GetOriginShape();
    auto w_i2h_shape = context->GetInputShape(2)->GetOriginShape();
    auto w_h2o_shape = context->GetInputShape(4)->GetOriginShape();

    uint32_t T = static_cast<uint32_t>(x_shape.GetDim(0));
    uint32_t B = static_cast<uint32_t>(x_shape.GetDim(1));
    uint32_t I = static_cast<uint32_t>(x_shape.GetDim(2));
    uint32_t H = static_cast<uint32_t>(w_i2h_shape.GetDim(0));
    uint32_t O = static_cast<uint32_t>(w_h2o_shape.GetDim(0));

    // blockDim equals batch size; each block processes one batch row for all time steps
    uint32_t blockDim = B;
    if (blockDim < 1) blockDim = 1;
    // Cap blockDim for resource limits (Ascend 910b max 24)
    if (blockDim > 24) blockDim = 24;

    context->SetBlockDim(blockDim);

    // totalLength not directly needed, set to output size for completeness
    uint32_t totalLength = T * B * O;
    tiling.set_totalLength(totalLength);
    tiling.set_T(T);
    tiling.set_B(B);
    tiling.set_I(I);
    tiling.set_H(H);
    tiling.set_O(O);
    tiling.set_blockDim(blockDim);

    tiling.SaveToBuffer(context->GetRawTilingData()->GetData(),
                        context->GetRawTilingData()->GetCapacity());
    context->GetRawTilingData()->SetDataSize(tiling.GetDataSize());

    size_t *currentWorkspace = context->GetWorkspaceSizes(1);
    currentWorkspace[0] = 0;
    return ge::GRAPH_SUCCESS;
}

} // namespace optiling

namespace ge {
static ge::graphStatus InferShape(gert::InferShapeContext *context)
{
    const gert::Shape *x_shape = context->GetInputShape(0);
    gert::Shape *y_shape = context->GetOutputShape(0);
    *y_shape = *x_shape;  // y shape: (T, B, O) will be set by tiling? Actually we need O dimension.
    // Override last dim to O (output dimension)
    auto w_h2o_shape = context->GetInputShape(4)->GetOriginShape();
    uint32_t O = static_cast<uint32_t>(w_h2o_shape.GetDim(0));
    y_shape->SetDim(2, static_cast<int64_t>(O));
    return GRAPH_SUCCESS;
}

static ge::graphStatus InferDataType(gert::InferDataTypeContext *context)
{
    const ge::DataType x_dtype = context->GetInputDataType(0);
    context->SetOutputDataType(0, x_dtype);
    return GRAPH_SUCCESS;
}
